mapper.select:
select merged.stats_date,
       coalesce(success.success_count, 0) as success_count,
       coalesce(failure.failed_attempts, 0) as failed_attempts
from (
         select check_in_date as stats_date
         from check_in_record
         where user_id = #{userId}
           and check_in_date between #{startDate} and #{endDate}
         union
         select check_in_date as stats_date
         from check_in_fail_record
         where user_id = #{userId}
           and check_in_date between #{startDate} and #{endDate}
     ) merged
         left join (
             select check_in_date,
                    count(1) as success_count
             from check_in_record
             where user_id = #{userId}
               and check_in_date between #{startDate} and #{endDate}
             group by check_in_date
         ) success on merged.stats_date = success.check_in_date
         left join (
             select check_in_date,
                    coalesce(sum(attempt_count), 0) as failed_attempts
             from check_in_fail_record
             where user_id = #{userId}
               and check_in_date between #{startDate} and #{endDate}
             group by check_in_date
         ) failure on merged.stats_date = failure.check_in_date
order by merged.stats_date asc
